assignments.value:
={{
(
  ($json.fieldFirstName ?? '') + 
  ($json.fieldLastName ?? '')
)
.normalize('NFD')
.replace(/[\u0300-\u036f]/g, '')
.replace(/[^a-zA-Z0-9]/g, '')
.toLowerCase() + '_' + $node["Form signup for Wordpress in KlickTipp form"].json.id
}}

={{ 
  // Generate a random 12-digit numeric password

  // Step 1: Math.random() generates a number between 0 and 1
  // Step 2: Multiply by 900000000000 to get a range of 0–899999999999
  // Step 3: Add 100000000000 so the number is always 12 digits (no leading zero issue)
  // Step 4: Math.floor() removes decimals
  // Step 5: Convert to string so n8n treats it as text

  Math.floor(100000000000 + Math.random() * 900000000000).toString()
}}

dataFields.fieldValue:
={{
  // Get the HTML content from the WordPress node
  $('Get last comments from Wordpress').item.json.content.rendered

    // Remove all HTML tags (anything between < and >)
    .replace(/<[^>]*>/g, '')

    // Remove leading and trailing whitespace
    .trim()
}}
